INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-08100', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有能力的社會工作人員在不侵犯他人的權力與尊嚴下，會自我表達其專業知識與意見的能力，這是具備何 種專業特質？', '["自我控制（self -control）", "自我瞭解（self -understanding）", "自我檢視（self -examination）", "專業責任的自我肯定（responsible assertiveness）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08101', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社會工作的服務過程中，案主有時陷入他特定的想法與所遭遇的障礙情境中而無法改變。社會工作者運 用新的方式來幫助案主重新認識自己，使其從獨斷的觀念中解放出來，這是運用何種專業技巧？', '["立即性反應（responding with immediacy）的技巧", "重新建構（reframing）的技巧", "面質（confronting）的技巧", "代理（representing）的技巧"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08102', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作核心任務是為弱勢者進行「反歧視實務」，下列敘述何者不符合「反歧視實務」之原則？', '["在執行任務時應考慮結構性弱勢，並試圖減少個別及制度性歧視", "在執行任務時應給被壓迫者充權（empowerment），使其從被壓迫的處境中解放出來", "在執行任務時遵守公正、平等、參與三個原則", "在執行任務時採取「中立」的行動"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08103', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '近年來，外籍配偶服務成為婦女福利服務的重要議題。社會工作者需要發展出對自我的覺察與探索文化差 異的技能，並瞭解不同文化的案主及其家庭能力，以有效協助不同文化背景的案主及其家庭。此種實務工 作模式是立基於何種理念？', '["社會排除", "多元文化主義", "全球化", "文化擴散"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08104', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者在社區照顧實務上，所使用的充權（empowerment）策略是讓社區中的失能者，對其社會角色與 社會地位的期待與一般人相同，進而朝向被社會視為有價值的人而努力，並與現有的社會整合，這是採取 何種策略？', '["自決（self-determination）", "自我倡導（self-advocacy）", "社會角色的管理（social role management）", "社會角色的激發（social role valorization,SRV）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08105', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關診斷派社會工作理論的敘述，何者為非？', '["診斷派認為人的成長取決於童年早期經驗所遺留於心靈深處的潛意識", "診斷派認為治療者與案主之間是平等互惠的治療關係", "診斷派認為治療的任務是幫助案主適應「現在」的環境", "診斷派的理論基礎是立基於佛洛依德的精神分析理論"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08106', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關功能派社會工作理論的敘述，下列何者為非？', '["功能派認為人的成長是由當事者的理念與目標所引導", "功能派認為治療者與案主之間是平等的關係", "功能派認為治療任務不僅針對現有問題所在，更在於案主未來的自我成長", "功能派不重視時間因素對案主的影響"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08107', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '認知行為治療法（CBT）不同的派別有不同的處遇模式，若要治療具有「社交恐懼症」的個案，下列那一項 陳述是正確的？', '["「古典制約法」實施方式：讓案主逐步暴露於恐懼事件下，並對成功的暴露給予正面強化", "「操作制約法」實施方式：提供案主一位新的模仿對象，對方不怕社交活動，並受到鼓勵去出席社交活動", "「認知學派」實施方式：改變案主負面思想，培養正面預期，並傳授社交技巧", "「模仿學派」實施方式：對案主用系統減敏和放鬆法訓練，切斷與恐懼事件的聯繫"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08108', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '對於「優勢觀點」（strengths perspective）的敘述，下列何者為非？', '["個人發展的可能性是無限制的", "服務使用者本身才是生活中的專家", "以因果直線思考邏輯和方法來減輕或緩和問題的徵兆", "童年的創傷不具斷定性，它可能是減弱成年人優勢之因，但也可能是增強優勢的學習"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08109', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關「生態系統理論」的敘述，下列何者為非？', '["生態探究法源自於社會達爾文主義、帕克（Park）的人類生態學", "強調人與其所處的社會環境之間的交互作用", "是以一個多層面和多系統之全人概念探討個人的社會功能", "強調透過干預個體內在心理來解決問題"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
